        "issue": "Local File Inclusion (LFI) in NextGEN Gallery",
        "impact": "Arbitrary file read on the server filesystem. Can lead to source code theft, .htpasswd retrieval, or RCE if log poisoning is possible.",
        "likelihood": "High"
      },
      {
        "issue": "Sensitive Data Exposure (Password Hashes)",
        "impact": "Exposure of password hashes allows offline cracking, leading to credential compromise.",
        "likelihood": "High"
      }
    ],
    "attack_vectors": [
      "Exploit hardcoded secrets to gain direct database access and pivot to internal services.",
      "Leverage unauthenticated API endpoints to harvest user tokens and perform IDOR attacks.",
